import{_ as a,o as r,c as o,a2 as l}from"./chunks/framework.DnrXFDHb.js";const g=JSON.parse('{"title":"算电协同2026：AI 时代的能源基础设施","description":"","frontmatter":{},"headers":[],"relativePath":"算电协同/算电协同2026.md","filePath":"算电协同/算电协同2026.md","lastUpdated":1782213036000}'),e={name:"算电协同/算电协同2026.md"};function i(n,t,s,h,p,d){return r(),o("div",null,[...t[0]||(t[0]=[l('<h1 id="算电协同2026-ai-时代的能源基础设施" tabindex="-1">算电协同2026：AI 时代的能源基础设施 <a class="header-anchor" href="#算电协同2026-ai-时代的能源基础设施" aria-label="Permalink to &quot;算电协同2026：AI 时代的能源基础设施&quot;">​</a></h1><p><strong>2026-06-12 | 陈道雷</strong></p><blockquote><p>如果说2025年是&quot;百模大战&quot;，那2026年最值得一级市场投资人关注的，不是又一个大模型，而是藏在算力背后的电。</p></blockquote><hr><h2 id="引子-一个正在发生的矛盾" tabindex="-1">引子：一个正在发生的矛盾 <a class="header-anchor" href="#引子-一个正在发生的矛盾" aria-label="Permalink to &quot;引子：一个正在发生的矛盾&quot;">​</a></h2><p>2026年Q1，中国数据中心用电量同比 +28%。</p><p>与此同时，全国电力现货市场均价同比下降 12%。</p><p>两个方向的数据放在一起，揭示了一个结构性变化：<strong>算力在爆炸式增长，但电价在降——不是因为电太多，而是因为电太贵的地方，算力正把它搬到电便宜的地方去。</strong></p><p>这就是算电协同。</p><p>去年我写&quot;六张网&quot;的时候，算电协同还是个概念。今年它已经进了政府工作报告，成了新型电力系统的核心组成。</p><p>但概念到投资之间，有一面隐形的墙。今天我试着把这面墙拆开来看。</p><hr><h2 id="一、先看三组数据" tabindex="-1">一、先看三组数据 <a class="header-anchor" href="#一、先看三组数据" aria-label="Permalink to &quot;一、先看三组数据&quot;">​</a></h2><h3 id="_1-1-算力有多渴" tabindex="-1">1.1 算力有多渴？ <a class="header-anchor" href="#_1-1-算力有多渴" aria-label="Permalink to &quot;1.1 算力有多渴？&quot;">​</a></h3><p>2026年中国数据中心用电量预计 <strong>3000亿 kWh</strong>，占全社会用电量 3.5%。</p><p>什么概念？相当于 <strong>1.5 个三峡电站全年发电量</strong>全部给数据中心。</p><p>这还不是终点。AI 训练和推理的算力需求还在以每年 50-80% 的速度增长。到 2028 年，数据中心用电占比可能超过 5%。</p><h3 id="_1-2-电有多贵" tabindex="-1">1.2 电有多贵？ <a class="header-anchor" href="#_1-2-电有多贵" aria-label="Permalink to &quot;1.2 电有多贵？&quot;">​</a></h3><p>数据中心用电成本占运营成本的 <strong>30-60%</strong>。</p><p>一个千P智算中心，年用电量 3-5 亿 kWh，按 0.5 元/度的均价，光电费就是 <strong>1.5-2.5 亿/年</strong>。</p><p>电费省 10%，就是 1500-2500 万的利润增量。对毛利率 30-40% 的数据中心来说，这是决定生死的数字。</p><h3 id="_1-3-时空错配有多严重" tabindex="-1">1.3 时空错配有多严重？ <a class="header-anchor" href="#_1-3-时空错配有多严重" aria-label="Permalink to &quot;1.3 时空错配有多严重？&quot;">​</a></h3><table tabindex="0"><thead><tr><th>错配类型</th><th>现状</th><th>机会</th></tr></thead><tbody><tr><td>时间错配</td><td>AI训练多在夜间低谷（电价低），推理在白天高峰（电价高）</td><td>训练任务可调度→电价套利</td></tr><tr><td>空间错配</td><td>算力集中在东部→电从西部来→输电损耗 5-8%</td><td>算力西迁→绿电直购</td></tr><tr><td>市场错配</td><td>电网要稳定、数据中心要低价、政府要碳排</td><td>三方共赢模式</td></tr></tbody></table><p>三组数据指向同一个结论：<strong>算电协同不是可选项，是必选项。</strong></p><hr><h2 id="二、三层机会" tabindex="-1">二、三层机会 <a class="header-anchor" href="#二、三层机会" aria-label="Permalink to &quot;二、三层机会&quot;">​</a></h2><p>我把算电协同的投资机会拆成三层：</p><h3 id="第一层-设备层-看得见的钱" tabindex="-1">第一层：设备层（看得见的钱） <a class="header-anchor" href="#第一层-设备层-看得见的钱" aria-label="Permalink to &quot;第一层：设备层（看得见的钱）&quot;">​</a></h3><p>液冷散热、高效UPS、储能系统、智能配电。</p><p><strong>2026年市场规模：</strong> 液冷散热 50-80 亿</p><p><strong>投资逻辑：</strong></p><ul><li>冷板式液冷已商用，PUE 能从 1.4 降到 1.2</li><li>浸没式液冷还能更低（PUE&lt;1.05），但技术路线未定</li><li>确定性高，但竞争激烈，适合产业资本</li></ul><p><strong>一级市场的机会不在设备，在平台。</strong></p><h3 id="第二层-平台层-看不见的钱-✅-重点" tabindex="-1">第二层：平台层（看不见的钱 ✅ 重点） <a class="header-anchor" href="#第二层-平台层-看不见的钱-✅-重点" aria-label="Permalink to &quot;第二层：平台层（看不见的钱 ✅ 重点）&quot;">​</a></h3><p>这是我最看好的方向。</p><ul><li><strong>AI 电力交易平台</strong>：电力现货市场扩容→交易频次增加→AI 报价策略需求爆发</li><li><strong>算力调度平台</strong>：跨区域/跨云调度，网络效应强</li><li><strong>VPP 聚合平台</strong>：把分散的数据中心聚合成虚拟电厂</li></ul><p><strong>为什么平台型机会大？</strong></p><ol><li>壁垒是数据和算法，不是资本——适合 PE/VC</li><li>网络效应：签约的客户越多，平台越值钱</li><li>轻资产：资本效率远高于设备层</li></ol><h3 id="第三层-模式层-未来的钱" tabindex="-1">第三层：模式层（未来的钱） <a class="header-anchor" href="#第三层-模式层-未来的钱" aria-label="Permalink to &quot;第三层：模式层（未来的钱）&quot;">​</a></h3><p>源网荷储一体化、绿电 PPA、数据中心+储能联合优化。</p><p>这些还太早，商业模式不清晰。<strong>可以先关注，不着急出手。</strong></p><hr><h2 id="三、三句话判断" tabindex="-1">三、三句话判断 <a class="header-anchor" href="#三、三句话判断" aria-label="Permalink to &quot;三、三句话判断&quot;">​</a></h2><blockquote><p><strong>第一句：算电协同的本质不是技术问题，是利益分配问题。</strong> 能同时让电网、数据中心、政府三方受益的模式才是好模式。</p></blockquote><blockquote><p><strong>第二句：最快落地的是需求响应，最大机会在 AI 交易。</strong> 需求响应有电改 2.0 驱动，AI 交易有 AI Agent 技术驱动。</p></blockquote><blockquote><p><strong>第三句：设备是二级市场的，平台是一级市场的。</strong> 投平台，不投设备。</p></blockquote><hr><h2 id="四、哪些方向值得出手" tabindex="-1">四、哪些方向值得出手？ <a class="header-anchor" href="#四、哪些方向值得出手" aria-label="Permalink to &quot;四、哪些方向值得出手？&quot;">​</a></h2><h3 id="p0-优先布局" tabindex="-1">P0（优先布局） <a class="header-anchor" href="#p0-优先布局" aria-label="Permalink to &quot;P0（优先布局）&quot;">​</a></h3><p><strong>AI 电力交易平台</strong></p><ul><li>为什么：电力现货市场扩容→交易频次×10 倍→AI 策略刚需</li><li>关键验证：有没有真实交易数据？夏普比率多少？</li><li>代表：瓦特智能、清大科越</li></ul><p><strong>算力调度平台</strong></p><ul><li>为什么：跨区域调度需求随算力增长指数上升</li><li>关键验证：签约算力规模？客户留存率？</li><li>代表：算力互联、星链算力</li></ul><h3 id="p1-重点跟踪" tabindex="-1">P1（重点跟踪） <a class="header-anchor" href="#p1-重点跟踪" aria-label="Permalink to &quot;P1（重点跟踪）&quot;">​</a></h3><p><strong>数据中心需求响应平台</strong></p><ul><li>政策驱动确定性强，2025 年内蒙古已首批试点</li><li>2026 年长三角数据中心 VPP 试点启动</li></ul><p><strong>VPP 聚合数据中心平台</strong></p><ul><li>AI+能源交叉，增长快</li><li>壁垒在客户资源和运营能力</li></ul><hr><h2 id="五、需要警惕的" tabindex="-1">五、需要警惕的 <a class="header-anchor" href="#五、需要警惕的" aria-label="Permalink to &quot;五、需要警惕的&quot;">​</a></h2><ol><li><strong>商业模式成熟度</strong> — 需求响应收益机制还在试点，谁出钱还没完全想清楚</li><li><strong>政策风险</strong> — 电改 2.0 进度可能不及预期</li><li><strong>复合人才稀缺</strong> — 既懂电力又懂 AI 的团队凤毛麟角</li><li><strong>估值泡沫</strong> — 赛道热了，跟风项目多，DD 要严</li></ol><hr><h2 id="写在最后" tabindex="-1">写在最后 <a class="header-anchor" href="#写在最后" aria-label="Permalink to &quot;写在最后&quot;">​</a></h2><p>算电协同是少见的<strong>政策、技术、经济三驱动叠加</strong>的赛道。</p><p>但越是热赛道，越要保持清醒。</p><p>建这面墙，不是为了挡住投资者，而是为了让真正看懂的人通过——那些想赚快钱的人，会被挡在墙外，而真正的长期主义者，会仔细拆解每一个环节，找到那个最坚实的支点，然后把它变成自己的护城河。</p><p>以上仅为我个人基于公开信息的分析推演，不构成投资建议。</p><hr><p><em>陈道雷 | 2026年6月</em><em>汇竑资本 · 研究出品</em></p>',69)])])}const c=a(e,[["render",i]]);export{g as __pageData,c as default};
